  var _SAIP_WIZARD_FPLMN = _saipPlmnListWizard({
    slotCount: 4,
    title: "EF.FPLMN wizard",
    spec: "3GPP TS 31.102 §4.2.16 — Forbidden PLMN list (default 4 slots × 3 B).",
    applyLabel: "Apply FPLMN",
  });

  var _SAIP_WIZARD_EHPLMN = _saipPlmnListWizard({
    slotCount: 5,
    title: "EF.EHPLMN wizard",
    spec: "3GPP TS 31.102 §4.2.84 — Equivalent HPLMN list (variable, typically 5 slots).",
    applyLabel: "Apply EHPLMN",
  });

  var _SAIP_WIZARD_PLMNWACT = _saipPlmnwActWizard({
    slotCount: 8,
    title: "EF.PLMNwAcT wizard",
    spec: "3GPP TS 31.102 §4.2.5 — User-controlled PLMN selector with Access Technologies.",
    applyLabel: "Apply PLMNwAcT",
  });

  var _SAIP_WIZARD_OPLMNWACT = _saipPlmnwActWizard({
    slotCount: 8,
    title: "EF.OPLMNwAcT wizard",
    spec: "3GPP TS 31.102 §4.2.53 — Operator-controlled PLMN selector with Access Technologies.",
    applyLabel: "Apply OPLMNwAcT",
  });

  var _SAIP_WIZARD_HPLMNWACT = _saipPlmnwActWizard({
    slotCount: 1,
    title: "EF.HPLMNwAcT wizard",
    spec: "3GPP TS 31.102 §4.2.54 — HPLMN selector with Access Technologies (single slot by default).",
    applyLabel: "Apply HPLMNwAcT",
  });

  // 3GPP TS 31.102 §4.2.15 — Access Control Class.
  // Two bytes; AC 15..11 in the high byte (bits b8..b4), special
  // class 10 bit at b3 of byte 1 (acts as "no AC 10 backoff"),
  // AC 9..0 in the low byte. b2/b1 of byte 1 are RFU.
