      // The standard encoding (TS 31.102 §4.2.15) places AC0 at b1
      // of byte 2 and AC15 at b8 of byte 1. We follow that mapping.

      // Rebuild correctly per the spec table:
      // byte 1:  b8=AC15  b7=AC14  b6=AC13  b5=AC12  b4=AC11
      //          b3=class10  b2..b1=RFU (0)
      // byte 2:  b8=AC7  b7=AC6  b6=AC5  b5=AC4  b4=AC3  b3=AC2  b2=AC1  b1=AC0
