      // a separate special class. Reissue the form below.
      classes = [];
      var acDefs = [
        // (label, byte_index, bit_mask)
        { n: 0,  byte: 1, mask: 0x01 },
        { n: 1,  byte: 1, mask: 0x02 },
        { n: 2,  byte: 1, mask: 0x04 },
        { n: 3,  byte: 1, mask: 0x08 },
        { n: 4,  byte: 1, mask: 0x10 },
        { n: 5,  byte: 1, mask: 0x20 },
        { n: 6,  byte: 1, mask: 0x40 },
        { n: 7,  byte: 1, mask: 0x80 },
        { n: 11, byte: 0, mask: 0x10 },
        { n: 12, byte: 0, mask: 0x20 },
        { n: 13, byte: 0, mask: 0x40 },
        { n: 14, byte: 0, mask: 0x80 },
        { n: 15, byte: 0, mask: 0x100 }, // bit b8 of byte 0; computed below
      ];
