      // Add the "class 10" / random-backoff bit (b3 of byte 0).
      acDefs.push({ n: -1, byte: 0, mask: 0x04, label: "AC 10 (random backoff)" });

      var grid = document.createElement("div");
      grid.className = "saip-wizard-bitgrid saip-wizard-acc-grid";
      var cbs = [];
      acDefs.forEach(function (def) {
        var label = (def.n >= 0) ? ("AC " + def.n) : def.label;
        var current = (def.byte === 0)
          ? ((b0 & def.mask) !== 0)
          : ((b1 & def.mask) !== 0);
        var cell = document.createElement("label");
        cell.className = "saip-wizard-bit-cell";
        var cb = document.createElement("input");
        cb.type = "checkbox";
        cb.checked = current;
        cb.dataset.byte = String(def.byte);
        cb.dataset.mask = String(def.mask);
        var span = document.createElement("span");
        span.textContent = label;
        cell.appendChild(cb);
        cell.appendChild(span);
        grid.appendChild(cell);
        cbs.push(cb);
      });
      _saipWizardRow(host, "Access classes", grid,
        "AC 0-9 = normal users · AC 11-15 = priority/PLMN staff · AC 10 = random backoff.");

      var preview = document.createElement("code");
      preview.className = "saip-wizard-preview";
      _saipWizardRow(host, "Encoded hex", preview, "Two bytes — high byte = AC 15..11 + class 10, low byte = AC 7..0.");

