        _saipWizardRow(host, "ASCII", asciiInput,
          "Optional. Empty cells pad with FF.");

        var hexInput = document.createElement("input");
        hexInput.type = "text";
        hexInput.className = "saip-wizard-text";
        hexInput.placeholder = "Hex (overrides ASCII when set)";
