      var gutiInput = document.createElement("input");
      gutiInput.type = "text";
      gutiInput.className = "saip-wizard-text saip-wizard-text--mono";
      gutiInput.maxLength = 24;
      gutiInput.value = _saipBytesToHex(bytes.slice(0, 12));
