  // EF.PSC (Phonebook Synchronisation Counter) — 4 B integer per
  // TS 31.102 §4.4.2.12.5.
  var _SAIP_WIZARD_PSC = {
    title: "EF.PSC wizard",
    spec: "3GPP TS 31.102 §4.4.2.12.5 — Phonebook Synchronisation Counter.",
    render: function (host, currentHex, applyFn) {
      var bytes = _saipHexToBytes(currentHex);
      while (bytes.length < 4) bytes.push(0x00);
      var input = document.createElement("input");
      input.type = "number";
      input.className = "saip-wizard-text";
      input.min = "0";
      input.value = String(
        ((bytes[0] & 0xFF) << 24)
        | ((bytes[1] & 0xFF) << 16)
        | ((bytes[2] & 0xFF) << 8)
        | (bytes[3] & 0xFF)
      );
      _saipWizardRow(host, "Counter (32-bit)", input,
        "Increments on each phonebook update.");
      _saipWizardApplyButton(host, "Apply PSC", function () {
        var n = parseInt(input.value, 10);
        if (!Number.isFinite(n) || n < 0 || n > 0xFFFFFFFF) {
          throw new Error("Counter must be 0..2^32-1.");
        }
        return { hex: _saipBytesToHex([
          (n >>> 24) & 0xFF,
          (n >>> 16) & 0xFF,
          (n >>> 8) & 0xFF,
          n & 0xFF,
        ]) };
      }, applyFn);
    },
  };

  // EF.CC (Phonebook Change Counter) — 2 B integer per
